        const function<bool(int, int)> dfs = [&](int i, int j) {
            if (!(i < size(grid) && j < size(grid[0]) && grid[i][j])) {
                return false;
            }
            if (i == size(grid) - 1 && j == size(grid[0]) - 1) {
                return true;
            }
            if (!(i == 0 && j == 0)) {
                grid[i][j] = 0;
            }
            return dfs(i + 1, j) || dfs(i, j + 1);
